testbench:
module testbench;

    reg clk;
    reg reset;
    wire [7:0] out;

    ring_counter ring_counter_inst (
        .clk(clk),
        .reset(reset),
        .out(out)
    );

    always begin
        #5 clk <= ~clk;
    end

    reg [3:0] i;

    function [7:0] expected_value;
        input [3:0] idx;
        begin
            case (idx)
                4'd0: expected_value = 8'b00000001;
                4'd1: expected_value = 8'b00000001;
                4'd2: expected_value = 8'b00000010;
                4'd3: expected_value = 8'b00000100;
                4'd4: expected_value = 8'b00001000;
                4'd5: expected_value = 8'b00010000;
                4'd6: expected_value = 8'b00100000;
                4'd7: expected_value = 8'b01000000;
                4'd8: expected_value = 8'b10000000;
                default: expected_value = 8'b00000001;
            endcase
        end
    endfunction

    initial begin
        clk = 0;
        reset = 1;
        i=0;
        #10 reset = 0;
    end
    // Monitor for displaying output
    always @(posedge clk) begin
        if (out !== expected_value(i)) begin
            $display("Failed at i=%d, out=%b, expected=%b", i, out, expected_value(i));
            // $finish;
        end
        i = i + 1;
    end

    // Stop simulation after checking all values
    always @(posedge clk) begin
        if (i == 9) begin
            $display("=========== Your Design Passed ===========");
            $finish;
        end
    end
    // Stop simulation after 100 clock cycles
    initial begin
        #100 $finish;
    end

endmodule

reference_rtl:
module ring_counter (
    input wire clk,
    input wire reset,
    output reg [7:0] out
);


reg [7:0] state;

// State initialization
always @ (posedge clk or posedge reset)
begin
    if (reset)
        state <= 8'b0000_0001; 
    else
        state <= {state[6:0], state[7]}; 
end

assign out = state;

endmodule
